INSERT INTO destinations (name, slug, category, region, description, image_url, rating, review_count, altitude_m, difficulty, best_months, featured) VALUES
('Rara Hidden Shore', 'rara-hidden-shore', 'Lake', 'Karnali Province', 'Secluded beach on Rara Lake. Camping spots away from main tourist area. Crystal clear water.', 'https://images.unsplash.com/photo-1439066615861-d1e4672a254d?w=800&q=80', 4.9, 56, 2990, 'Easy', ARRAY['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'], true),
